UPDATE analytics_view_share
SET import_count = import_count + 1
WHERE id = #{id}

UPDATE analytics_view_share
SET revoked = 1
WHERE owner_user_id = #{ownerUserId}
  AND source_view_id = #{sourceViewId}
  AND revoked = 0

UPDATE analytics_view_share
SET revoked = 1
WHERE id = #{id} AND owner_user_id = #{ownerUserId}
